from openai import OpenAI

client = OpenAI()

def summarize_event(event: dict):
    prompt = f"""
    Summarize this agent run into a concise summary (1–2 sentences):

    Goal: {event['goal']}
    Tools: {[step['tool'] for step in event['trace']]}
    Outcome: {event['outcome']['status']}
    Tokens: {event['outcome']['tokens_total']}

    Summary:
    """

    response = client.chat.completions.create(
        model="claude-3.5",
        messages=[{"role": "user", "content": prompt}]
    )

    return response.choices[0].message.content

# Generate summaries for all events
summaries = [summarize_event(event) for event in recent_events]

# Prune events older than 1 year
old_events = db.query(
    filter={"timestamp": {"$lt": now - 1y}}
)
db.delete(old_events)

# Extract preferences from successful runs
preferences = []
for pattern in patterns:
    if pattern["type"] == "success":
        # Infer preference: "User prefers {tool}"
        preferences.append(f"User prefers {pattern['tools'][0]}")

# Store as semantic memory
for pref in preferences:
    vector = embed(pref)
    vector_db.upsert({
        "id": f"pref_{pref[:20]}",
        "values": vector,
        "metadata": {"type": "preference", "fact": pref}
    })
